import React, { useState } from 'react';
import Sidebar from '../components/Sidebar'; // <-- NEW IMPORT
import ProfileForm from '../components/ProfileForm';
import RiskForm from '../components/RiskForm';
import CalorieUpload from '../components/CalorieUpload';
import ProgressChart from '../components/ProgressChart';
import Recommendations from '../pages/Recommendations'; 
import NutrientWarning from '../components/NutrientWarning'; // Already imported but necessary

// Map module IDs to their corresponding components
const MODULE_COMPONENTS = {
    'profile': ProfileForm,
    'risk': RiskForm,
    'calorie': CalorieUpload,
    'recommendations': Recommendations,
    'analytics': ProgressChart,
};

// Systematically ordered menu (re-defined here for component fetching)
const DASHBOARD_MENU = [
    { id: 'profile', name: '👤 Profile & Goal' },
    { id: 'risk', name: '❤️ Health Risk Check' },
    { id: 'calorie', name: '🥗 Calorie Estimation' },
    { id: 'recommendations', name: '🧠 Personalized Plans' },
    { id: 'analytics', name: '📊 Daily Analytics' },
];


const Dashboard = ({ profile, setProfile, fetchProfile }) => {
    // State to track which item in the sidebar is active
    const [activeModule, setActiveModule] = useState('profile');
    
    // Find the component currently selected
    const ActiveComponent = MODULE_COMPONENTS[activeModule];
    
    // Check for essential data needed for BMI/BMR/Risk Calculation
    const isProfileIncomplete = !profile.age || !profile.height || !profile.weight;

    // Props passed to the active component
    const componentProps = {
        profile,
        setProfile,
        fetchProfile,
        dailyCalorieTarget: profile.dailyCalorieTarget,
    };
    
    // Determine the title of the active content pane
    const activeTitle = DASHBOARD_MENU.find(item => item.id === activeModule)?.name;


    // --- RENDERING ---
    return (
        // Main container split into sidebar and content
        <div className="flex min-h-[calc(100vh-68px)] bg-[#0D1117] text-white">

            {/* Left Sidebar (20%) */}
            <Sidebar activeModule={activeModule} setActiveModule={setActiveModule} />

            {/* Right Content Area (80%) */}
            <div className="w-4/5 p-8 bg-[#0D1117] overflow-y-auto">
                <div className="bg-card p-6 rounded-xl shadow-ai border border-[#161B22]">
                    <h2 className="text-3xl font-bold mb-6 text-ai-green tracking-wide border-b border-[#2D333B] pb-3">
                        {activeTitle}
                    </h2>

                    {/* Conditional Rendering of the Active Module */}
                    <div className="min-h-[600px]">
                        {ActiveComponent && (
                            // Apply conditional rendering for modules that require data setup
                            (activeModule === 'risk' && isProfileIncomplete) ? (
                                <p className="text-red-500 p-8">
                                    Please complete Age, Height, and Weight in the **Profile & Goal** module to run this diagnosis.
                                </p>
                            ) : (
                                <ActiveComponent {...componentProps} />
                            )
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;
